/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Strategy Reviews & Ratings
   Social feature: community-driven strategy quality feedback with ratings,
   reviews, and helpfulness voting.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useState, useEffect, useMemo, useCallback } from 'react';
import { tokens } from '../styles/tokens';
import GlassPanel from './ui/GlassPanel';
import { api, apiPost } from '../utils/api';

// ── Design tokens ─────────────────────────────────────────────────────────
const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple, cyan: tokens.color.cyan,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

// ── Star colors ───────────────────────────────────────────────────────────
const STAR_FILLED = T.amber;
const STAR_EMPTY = T.surface2;

// ── Demo reviews (shown when API doesn't have reviews yet) ────────────────
const DEMO_REVIEWS = [
  { id: 1, user: 'TraderMike', rating: 5, text: 'Consistently profitable on tech stocks. The pullback detection is excellent.', date: '2026-03-15', helpful: 12 },
  { id: 2, user: 'AlgoSarah', rating: 4, text: 'Good win rate but drawdowns can be deep during regime changes. Pair with a defensive strategy.', date: '2026-03-12', helpful: 8 },
  { id: 3, user: 'QuantJosh', rating: 4, text: 'Solid on large-caps. Less reliable on small-caps under $10. Overall a strong addition to the portfolio.', date: '2026-03-08', helpful: 5 },
  { id: 4, user: 'NoviceTrader22', rating: 5, text: 'My first strategy on the platform. Easy to understand the signals and the backtest results gave me confidence to go live.', date: '2026-03-05', helpful: 3 },
];

// ── Rating distribution bars (colors) ─────────────────────────────────────
const BAR_COLORS = {
  5: T.green,
  4: T.green,
  3: T.amber,
  2: T.amber,
  1: T.red,
};

// ── Avatar color by username hash ─────────────────────────────────────────
const AVATAR_COLORS = [T.blue, T.green, T.purple, T.amber, T.cyan, T.red, T.red, T.blue];
function avatarColor(name) {
  let hash = 0;
  for (let i = 0; i < name.length; i++) {
    hash = name.charCodeAt(i) + ((hash << 5) - hash);
  }
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

// ═══════════════════════════════════════════════════════════════════════════
// StarRating — reusable star display/selector
// ═══════════════════════════════════════════════════════════════════════════
function StarRating({ rating, maxStars = 5, size = 14, interactive = false, onChange }) {
  const [hoverRating, setHoverRating] = useState(0);

  const displayRating = interactive && hoverRating > 0 ? hoverRating : rating;

  const stars = [];
  for (let i = 1; i <= maxStars; i++) {
    const diff = displayRating - i + 1;
    // Full, half, or empty
    let fillType = 'empty';
    if (diff >= 1) fillType = 'full';
    else if (diff >= 0.25) fillType = 'half';

    stars.push(
      <span
        key={i}
        onClick={interactive ? () => onChange?.(i) : undefined}
        onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
        onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
        style={{
          cursor: interactive ? 'pointer' : 'default',
          display: 'inline-block',
          position: 'relative',
          width: size,
          height: size,
          marginRight: 4,
        }}
      >
        <svg width={size} height={size} viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
          {/* Background (empty) star */}
          <path
            d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"
            fill={STAR_EMPTY}
          />
          {/* Filled star (full or half via clipPath) */}
          {fillType !== 'empty' && (
            <>
              {fillType === 'half' && (
                <defs>
                  <clipPath id={`half-clip-${size}-${i}`}>
                    <rect x="0" y="0" width="12" height="24" />
                  </clipPath>
                </defs>
              )}
              <path
                d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"
                fill={STAR_FILLED}
                clipPath={fillType === 'half' ? `url(#half-clip-${size}-${i})` : undefined}
              />
            </>
          )}
        </svg>
      </span>
    );
  }

  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', lineHeight: 1 }}>
      {stars}
    </span>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
// MAIN COMPONENT
// ═══════════════════════════════════════════════════════════════════════════
export default function StrategyReviews({ strategyKey, strategyLabel }) {
  const [reviews, setReviews] = useState([]);
  const [isDemo, setIsDemo] = useState(false);
  const [loading, setLoading] = useState(true);
  const [sortBy, setSortBy] = useState('helpful'); // helpful | recent | highest
  const [showForm, setShowForm] = useState(false);
  const [formRating, setFormRating] = useState(0);
  const [formText, setFormText] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);
  const [helpedIds, setHelpedIds] = useState(new Set());

  // ── Fetch reviews from API, fallback to demo ──────────────────────────
  useEffect(() => {
    let cancelled = false;
    async function load() {
      setLoading(true);
      try {
        const data = await api(`/strategies/${encodeURIComponent(strategyKey)}/reviews`, { silent: true });
        if (!cancelled) {
          if (data && Array.isArray(data) && data.length > 0) {
            setReviews(data);
            setIsDemo(false);
          } else {
            setReviews(DEMO_REVIEWS);
            setIsDemo(true);
          }
        }
      } catch {
        if (!cancelled) {
          setReviews(DEMO_REVIEWS);
          setIsDemo(true);
        }
      }
      if (!cancelled) setLoading(false);
    }
    load();
    return () => { cancelled = true; };
  }, [strategyKey]);

  // ── Computed stats ────────────────────────────────────────────────────
  const stats = useMemo(() => {
    if (reviews.length === 0) return { avg: 0, count: 0, dist: { 5: 0, 4: 0, 3: 0, 2: 0, 1: 0 } };
    const sum = reviews.reduce((a, r) => a + r.rating, 0);
    const avg = sum / reviews.length;
    const dist = { 5: 0, 4: 0, 3: 0, 2: 0, 1: 0 };
    reviews.forEach(r => { if (dist[r.rating] !== undefined) dist[r.rating]++; });
    return { avg, count: reviews.length, dist };
  }, [reviews]);

  // ── Sort reviews ──────────────────────────────────────────────────────
  const sortedReviews = useMemo(() => {
    const sorted = [...reviews];
    if (sortBy === 'helpful') sorted.sort((a, b) => (b.helpful || 0) - (a.helpful || 0));
    else if (sortBy === 'recent') sorted.sort((a, b) => (b.date || '').localeCompare(a.date || ''));
    else if (sortBy === 'highest') sorted.sort((a, b) => b.rating - a.rating);
    return sorted;
  }, [reviews, sortBy]);

  // ── Submit review ─────────────────────────────────────────────────────
  const handleSubmit = useCallback(async () => {
    if (formRating === 0 || formText.trim().length === 0) return;
    setSubmitting(true);

    const newReview = {
      id: Date.now(),
      user: 'You',
      rating: formRating,
      text: formText.trim(),
      date: new Date().toISOString().slice(0, 10),
      helpful: 0,
    };

    // Optimistically add to local state
    setReviews(prev => [newReview, ...prev]);
    setSubmitSuccess(true);
    setFormRating(0);
    setFormText('');
    setShowForm(false);

    // Try POST to API (fire and forget)
    try {
      await apiPost(`/strategies/${encodeURIComponent(strategyKey)}/reviews`, {
        rating: newReview.rating,
        text: newReview.text,
      });
    } catch {
      // API may not exist yet — review stays in local state
    }

    setSubmitting(false);
    setTimeout(() => setSubmitSuccess(false), 4000);
  }, [formRating, formText, strategyKey]);

  // ── Mark helpful ──────────────────────────────────────────────────────
  const markHelpful = useCallback((id) => {
    if (helpedIds.has(id)) return;
    setHelpedIds(prev => new Set(prev).add(id));
    setReviews(prev => prev.map(r => r.id === id ? { ...r, helpful: (r.helpful || 0) + 1 } : r));
    // Try API (fire and forget)
    apiPost(`/strategies/${encodeURIComponent(strategyKey)}/reviews/${id}/helpful`, {}).catch(() => {});
  }, [helpedIds, strategyKey]);

  // ── Format date ───────────────────────────────────────────────────────
  const fmtDate = (d) => {
    if (!d) return '';
    try {
      const dt = new Date(d + 'T00:00:00');
      return dt.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    } catch { return d; }
  };

  // ── Loading ───────────────────────────────────────────────────────────
  if (loading) {
    return (
      <GlassPanel style={{ marginBottom: 24 }}>
        <div style={{ textAlign: 'center', padding: 32, color: T.textSec, fontFamily: T.mono, fontSize: 13 }}>
          Loading reviews...
        </div>
      </GlassPanel>
    );
  }

  return (
    <GlassPanel style={{ marginBottom: 24 }}>

      {/* ═══ HEADER ROW ═════════════════════════════════════════════════════ */}
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        flexWrap: 'wrap', gap: 12, marginBottom: 20,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          {/* Icon */}
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={T.amber} strokeWidth="2">
            <path d="M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z" />
          </svg>
          <span style={{ fontSize: 16, fontWeight: 700, color: T.text, fontFamily: T.sans }}>
            Community Reviews
          </span>
          <StarRating rating={stats.avg} size={16} />
          <span style={{ fontSize: 14, fontWeight: 700, color: T.amber, fontFamily: T.mono }}>
            {stats.avg.toFixed(1)}
          </span>
          <span style={{ fontSize: 13, color: T.textSec, fontFamily: T.sans }}>
            ({stats.count} {stats.count === 1 ? 'review' : 'reviews'})
          </span>
        </div>

        <button
          onClick={() => { setShowForm(!showForm); setSubmitSuccess(false); }}
          style={{
            padding: '8px 18px', borderRadius: 6, fontSize: 13, fontWeight: 700,
            background: showForm ? T.surface2 : 'transparent',
            border: `1px solid ${T.amber}55`,
            color: T.amber, cursor: 'pointer', fontFamily: T.mono,
            transition: 'all 0.15s', letterSpacing: '0.03em',
          }}
          onMouseEnter={(e) => { e.target.style.background = T.amber + '18'; }}
          onMouseLeave={(e) => { e.target.style.background = showForm ? T.surface2 : 'transparent'; }}
        >
          {showForm ? 'Cancel' : 'Write a Review'}
        </button>
      </div>

      {/* Demo banner */}
      {isDemo && (
        <div style={{
          padding: '6px 12px', borderRadius: 6, marginBottom: 16,
          background: T.purple + '10', border: `1px solid ${T.purple}22`,
          fontSize: 11, color: T.purple, fontFamily: T.sans,
        }}>
          Showing sample reviews. Be the first to review {strategyLabel || 'this strategy'}!
        </div>
      )}

      {/* Submit success message */}
      {submitSuccess && (
        <div style={{
          padding: '8px 14px', borderRadius: 6, marginBottom: 16,
          background: T.green + '12', border: `1px solid ${T.green}33`,
          fontSize: 13, color: T.green, fontFamily: T.sans, fontWeight: 600,
        }}>
          Your review has been submitted. Thank you for your feedback!
        </div>
      )}

      {/* ═══ WRITE REVIEW FORM (collapsible) ════════════════════════════════ */}
      {showForm && (
        <div style={{
          marginBottom: 20, padding: 16, borderRadius: 10,
          background: T.surface2, border: `1px solid ${T.border}`,
        }}>
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 13, color: T.textSec, marginBottom: 8, fontFamily: T.sans }}>
              Your rating
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <StarRating rating={formRating} size={26} interactive onChange={setFormRating} />
              {formRating > 0 && (
                <span style={{ fontSize: 13, color: T.amber, fontFamily: T.mono, fontWeight: 700 }}>
                  {formRating}/5
                </span>
              )}
            </div>
          </div>

          <div style={{ marginBottom: 16 }}>
            <textarea
              value={formText}
              onChange={(e) => setFormText(e.target.value)}
              placeholder="Share your experience with this strategy..."
              rows={4}
              style={{
                width: '100%', padding: 12, borderRadius: 10, fontSize: 13,
                fontFamily: T.sans, color: T.text, background: T.surface,
                border: `1px solid ${T.border}`, resize: 'vertical',
                outline: 'none', lineHeight: 1.6, boxSizing: 'border-box',
              }}
              onFocus={(e) => { e.target.style.borderColor = T.blue; }}
              onBlur={(e) => { e.target.style.borderColor = T.border; }}
            />
          </div>

          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <button
              onClick={handleSubmit}
              disabled={formRating === 0 || formText.trim().length === 0 || submitting}
              style={{
                padding: '8px 24px', borderRadius: 6, fontSize: 13, fontWeight: 700,
                background: (formRating === 0 || formText.trim().length === 0)
                  ? T.surface2 : T.amber + '22',
                border: `1px solid ${(formRating === 0 || formText.trim().length === 0)
                  ? T.border : T.amber + '55'}`,
                color: (formRating === 0 || formText.trim().length === 0)
                  ? T.textSec : T.amber,
                cursor: (formRating === 0 || formText.trim().length === 0)
                  ? 'not-allowed' : 'pointer',
                fontFamily: T.mono, transition: 'all 0.15s', letterSpacing: '0.03em',
                opacity: (formRating === 0 || formText.trim().length === 0) ? 0.5 : 1,
              }}
            >
              {submitting ? 'Submitting...' : 'Submit Review'}
            </button>
            {formRating === 0 && (
              <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.sans }}>
                Select a rating to continue
              </span>
            )}
          </div>
        </div>
      )}

      {/* ═══ RATING SUMMARY BAR ═════════════════════════════════════════════ */}
      <div style={{
        display: 'grid', gridTemplateColumns: '80px 1fr', gap: 20,
        marginBottom: 24, alignItems: 'center',
      }}>
        {/* Big average number */}
        <div style={{ textAlign: 'center' }}>
          <div style={{ fontSize: 36, fontWeight: 800, color: T.text, fontFamily: T.mono, lineHeight: 1 }}>
            {stats.avg.toFixed(1)}
          </div>
          <StarRating rating={stats.avg} size={13} />
          <div style={{ fontSize: 10, color: T.textSec, marginTop: 4, fontFamily: T.sans }}>
            {stats.count} {stats.count === 1 ? 'rating' : 'ratings'}
          </div>
        </div>

        {/* Distribution bars */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
          {[5, 4, 3, 2, 1].map(star => {
            const count = stats.dist[star] || 0;
            const pct = stats.count > 0 ? (count / stats.count) * 100 : 0;
            return (
              <div key={star} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.mono, width: 18, textAlign: 'right' }}>
                  {star}
                </span>
                <svg width="10" height="10" viewBox="0 0 24 24" fill={STAR_FILLED}>
                  <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
                </svg>
                <div style={{
                  flex: 1, height: 8, borderRadius: 9999,
                  background: T.surface2, overflow: 'hidden',
                }}>
                  <div style={{
                    width: `${pct}%`, height: '100%', borderRadius: 9999,
                    background: BAR_COLORS[star],
                    transition: 'width 0.4s ease',
                    minWidth: pct > 0 ? 4 : 0,
                  }} />
                </div>
                <span style={{ fontSize: 10, color: T.textSec, fontFamily: T.mono, width: 32, textAlign: 'right' }}>
                  {Math.round(pct)}%
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* ═══ SORT CONTROLS ══════════════════════════════════════════════════ */}
      <div style={{
        display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16,
        borderBottom: `1px solid ${T.border}`, paddingBottom: 12,
      }}>
        <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.sans, marginRight: 4 }}>Sort by:</span>
        {[
          { key: 'helpful', label: 'Most Helpful' },
          { key: 'recent', label: 'Most Recent' },
          { key: 'highest', label: 'Highest Rated' },
        ].map(opt => (
          <button
            key={opt.key}
            onClick={() => setSortBy(opt.key)}
            style={{
              padding: '4px 10px', borderRadius: 6, fontSize: 11, fontWeight: 600,
              background: sortBy === opt.key ? T.blue + '18' : 'transparent',
              border: sortBy === opt.key ? `1px solid ${T.blue}44` : `1px solid transparent`,
              color: sortBy === opt.key ? T.blue : T.textSec,
              cursor: 'pointer', fontFamily: T.sans, transition: 'all 0.15s',
            }}
            onMouseEnter={(e) => { if (sortBy !== opt.key) e.target.style.color = T.text; }}
            onMouseLeave={(e) => { if (sortBy !== opt.key) e.target.style.color = T.textSec; }}
          >
            {opt.label}
          </button>
        ))}
      </div>

      {/* ═══ REVIEW CARDS ═══════════════════════════════════════════════════ */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 0 }}>
        {sortedReviews.map((review, idx) => {
          const initial = (review.user || '?')[0].toUpperCase();
          const color = avatarColor(review.user || 'anon');
          const helped = helpedIds.has(review.id);

          return (
            <div
              key={review.id}
              style={{
                padding: '14px 0',
                borderBottom: idx < sortedReviews.length - 1
                  ? `1px solid ${T.border}` : 'none',
              }}
            >
              {/* Top row: avatar + user + date + stars */}
              <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 8 }}>
                {/* Avatar circle */}
                <div style={{
                  width: 32, height: 32, borderRadius: '50%',
                  background: color + '22', border: `1px solid ${color}44`,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 13, fontWeight: 700, color, fontFamily: T.sans,
                  flexShrink: 0,
                }}>
                  {initial}
                </div>

                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap' }}>
                    <span style={{ fontSize: 13, fontWeight: 700, color: T.text, fontFamily: T.sans }}>
                      {review.user}
                    </span>
                    <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.sans }}>
                      {fmtDate(review.date)}
                    </span>
                  </div>
                  <StarRating rating={review.rating} size={12} />
                </div>
              </div>

              {/* Review text */}
              <div style={{
                fontSize: 13, color: T.text, lineHeight: 1.6,
                fontFamily: T.sans, marginLeft: 42, marginBottom: 8,
              }}>
                {review.text}
              </div>

              {/* Helpful button */}
              <div style={{ marginLeft: 42 }}>
                <button
                  onClick={() => markHelpful(review.id)}
                  disabled={helped}
                  style={{
                    display: 'inline-flex', alignItems: 'center', gap: 8,
                    padding: '4px 10px', borderRadius: 6, fontSize: 11,
                    background: helped ? T.green + '12' : 'transparent',
                    border: `1px solid ${helped ? T.green + '33' : T.border}`,
                    color: helped ? T.green : T.textSec,
                    cursor: helped ? 'default' : 'pointer',
                    fontFamily: T.sans, transition: 'all 0.15s',
                  }}
                  onMouseEnter={(e) => { if (!helped) { e.target.style.borderColor = T.green + '44'; e.target.style.color = T.green; } }}
                  onMouseLeave={(e) => { if (!helped) { e.target.style.borderColor = T.border; e.target.style.color = T.textSec; } }}
                >
                  <svg width="12" height="12" viewBox="0 0 24 24" fill="none"
                    stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <path d="M14 9V5a3 3 0 00-3-3l-4 9v11h11.28a2 2 0 002-1.7l1.38-9a2 2 0 00-2-2.3H14z" />
                    <path d="M7 22H4a2 2 0 01-2-2v-7a2 2 0 012-2h3" />
                  </svg>
                  Helpful ({review.helpful || 0})
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {reviews.length === 0 && (
        <div style={{
          textAlign: 'center', padding: 32, color: T.textSec,
          fontFamily: T.sans, fontSize: 13,
        }}>
          No reviews yet. Be the first to share your experience!
        </div>
      )}
    </GlassPanel>
  );
}
