// ── Recent Signals Feed ────────────────────────────────────────────────────
const SIGNAL_FILTERS = ['All', 'Wins', 'Losses', 'Pending'];

function RecentSignalsFeed({ strategyName, trackSignals = [] }) {
  const [signals, setSignals] = useState([]);
  const [loadingSig, setLoadingSig] = useState(true);
  const [activeFilter, setActiveFilter] = useState('All');

  useEffect(() => {
    if (!strategyName) return;
    setLoadingSig(true);
    api(`/strategies/${encodeURIComponent(strategyName)}/signals?limit=20&days=30`)
      .then(data => {
        const list = Array.isArray(data) ? data : (data?.signals || []);
        // Merge track-record signals if they add new data
        const merged = [...list];
        if (trackSignals.length > 0) {
          const existingIds = new Set(merged.map(s => s.signal_id).filter(Boolean));
          trackSignals.forEach(ts => {
            if (ts.signal_id && !existingIds.has(ts.signal_id)) {
              merged.push(ts);
            }
          });
        }
        setSignals(merged);
      })
      .catch(() => setSignals(trackSignals))
      .finally(() => setLoadingSig(false));
  }, [strategyName, trackSignals]);

  // ── Derived stats ──────────────────────────────────────────────────────
  const withOutcome = signals.filter(sig => sig.outcome != null && sig.outcome !== 'pending');
  const wins   = withOutcome.filter(sig => (sig.pnl ?? sig.outcome_pnl ?? 0) > 0);
  const losses = withOutcome.filter(sig => (sig.pnl ?? sig.outcome_pnl ?? 0) <= 0);
  const pending = signals.filter(sig => sig.outcome == null || sig.outcome === 'pending');
  const avgPnl = withOutcome.length > 0
    ? withOutcome.reduce((acc, sig) => acc + (sig.pnl ?? sig.outcome_pnl ?? 0), 0) / withOutcome.length
    : null;

  // ── Filter logic ──────────────────────────────────────────────────────
  const filtered = signals.filter(sig => {
    if (activeFilter === 'All') return true;
    const isPending = sig.outcome == null || sig.outcome === 'pending';
    if (activeFilter === 'Pending') return isPending;
    if (isPending) return false;
    const pnl = sig.pnl ?? sig.outcome_pnl ?? 0;
    if (activeFilter === 'Wins') return pnl > 0;
    if (activeFilter === 'Losses') return pnl <= 0;
    return true;
  });

  // ── Row color ─────────────────────────────────────────────────────────
  const rowBg = (sig) => {
    const isPending = sig.outcome == null || sig.outcome === 'pending';
    if (isPending) return 'transparent';
    const pnl = sig.pnl ?? sig.outcome_pnl ?? 0;
    return pnl > 0 ? T.green + '0d' : T.red + '0d';
  };

  // ── Hold time display ─────────────────────────────────────────────────
  const fmtHold = (sig) => {
    if (sig.hold_hours != null) {
      const h = sig.hold_hours;
      return h < 24 ? `${h}h` : `${(h / 24).toFixed(1)}d`;
    }
    if (sig.hold_days != null) return `${sig.hold_days}d`;
    return null;
  };

  return (
    <GlassPanel style={{ marginBottom: 24 }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
        <div className={s.panelTitle} style={{ marginBottom: 0 }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.cyan} strokeWidth="2">
            <polyline points="22 12 18 12 15 21 9 3 6 12 2 12" />
          </svg>
          Recent Signals
        </div>
        {/* Summary badge */}
        {!loadingSig && signals.length > 0 && (
          <div className={s.sigFeedSummary}>
            <span style={{ color: T.text }}>{signals.length} signals</span>
            {withOutcome.length > 0 && (
              <>
                <span style={{ color: T.border }}>|</span>
                <span style={{ color: T.green }}>{wins.length}W</span>
                <span style={{ color: T.red }}>{losses.length}L</span>
                {avgPnl != null && (
                  <>
                    <span style={{ color: T.border }}>|</span>
                    <span style={{ color: avgPnl >= 0 ? T.green : T.red, fontWeight: 700 }}>
                      Avg {fmtDollar(avgPnl)}
                    </span>
                  </>
                )}
              </>
            )}
          </div>
        )}
      </div>

      {/* Filter buttons */}
      <div className={s.sigFeedFilters}>
        {SIGNAL_FILTERS.map(f => (
          <button
            key={f}
            onClick={() => setActiveFilter(f)}
            className={s.sigFeedFilterBtn}
            style={{
              color: activeFilter === f ? T.text : T.textSec,
              background: activeFilter === f ? T.blue + '22' : 'transparent',
              border: `1px solid ${activeFilter === f ? T.blue + '66' : T.border}`,
            }}
          >
            {f}
            {f === 'Wins' && wins.length > 0 && (
              <span className={s.sigFeedFilterCount} style={{ background: T.green + '33', color: T.green }}>
                {wins.length}
              </span>
            )}
            {f === 'Losses' && losses.length > 0 && (
              <span className={s.sigFeedFilterCount} style={{ background: T.red + '33', color: T.red }}>
                {losses.length}
              </span>
            )}
            {f === 'Pending' && pending.length > 0 && (
              <span className={s.sigFeedFilterCount} style={{ background: T.blue + '33', color: T.blue }}>
                {pending.length}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Content */}
      {loadingSig ? (
        <div style={{ fontSize: 13, color: T.textSec, padding: '16px 0', fontFamily: T.mono }}>
          Loading signals...
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ fontSize: 13, color: T.textSec, padding: '16px 0' }}>
          {signals.length === 0 ? 'No signals recorded in the last 30 days.' : `No ${activeFilter.toLowerCase()} signals.`}
        </div>
      ) : (
        <div className={s.sigFeedList}>
          {filtered.map((sig, idx) => {
            const isPending = sig.outcome == null || sig.outcome === 'pending';
            const pnl = sig.pnl ?? sig.outcome_pnl ?? null;
            const isLong = (sig.direction || '').toLowerCase() !== 'short';
            const holdStr = fmtHold(sig);
            const entryDate = sig.signal_date || sig.entry_date || '--';
            const exitDate  = sig.exit_date || null;

            return (
              <div
                key={sig.signal_id || idx}
                className={s.sigFeedRow}
                style={{ background: rowBg(sig) }}
              >
                {/* Symbol + direction */}
                <div className={s.sigFeedSymbol}>
                  <span
                    className={s.sigFeedArrow}
                    style={{ color: isLong ? T.green : T.red }}
                  >
                    {isLong ? '\u2191' : '\u2193'}
                  </span>
                  <span style={{ fontWeight: 700, fontFamily: T.mono, fontSize: 13 }}>
                    {sig.symbol || '--'}
                  </span>
                </div>

                {/* Entry price + date */}
                <div className={s.sigFeedEntry}>
                  <span style={{ fontFamily: T.mono, fontSize: 12, color: T.text }}>
                    {sig.entry_price != null ? `$${Number(sig.entry_price).toFixed(2)}` : '--'}
                  </span>
                  <span style={{ fontSize: 11, color: T.textSec, marginTop: 1 }}>
                    {entryDate}
                  </span>
                </div>

                {/* Outcome / P&L */}
                <div className={s.sigFeedOutcome}>
                  {isPending ? (
                    <span className={s.sigFeedBadgeOpen}>Open</span>
                  ) : (
                    <>
                      <span style={{
                        fontFamily: T.mono, fontSize: 13, fontWeight: 700,
                        color: pnl != null ? (pnl > 0 ? T.green : T.red) : T.textSec,
                      }}>
                        {pnl != null ? fmtDollar(pnl) : '--'}
                      </span>
                      {exitDate && (
                        <span style={{ fontSize: 11, color: T.textSec, marginTop: 1 }}>
                          {exitDate}
                        </span>
                      )}
                    </>
                  )}
                </div>

                {/* Hold time */}
                <div className={s.sigFeedHold}>
                  {holdStr ? (
                    <span style={{ fontFamily: T.mono, fontSize: 12, color: T.textSec }}>
                      {holdStr}
                    </span>
                  ) : (
                    <span style={{ color: T.border }}>&mdash;</span>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      )}
    </GlassPanel>
  );
}

// ── A/B Experiments Panel ─────────────────────────────────────────────────
function ABExperimentsPanel({ strategyName }) {
  const [experiments, setExperiments] = useState([]);
  const [modalOpen, setModalOpen] = useState(false);
  const [form, setForm] = useState({ name: '', vs: '', alloc: 50 });
  const [submitting, setSubmitting] = useState(false);

  const fetchExperiments = useCallback(async () => {
    try {
      const data = await api('/strategies/ab/experiments');
      const list = Array.isArray(data) ? data : (data?.experiments || []);
      setExperiments(list.filter(e =>
        e.strategy_a === strategyName || e.strategy_b === strategyName
      ));
    } catch { /* silent -- endpoint may not exist yet */ }
  }, [strategyName]);

  useEffect(() => { fetchExperiments(); }, [fetchExperiments]);

  const handleSubmit = async () => {
    if (!form.name || !form.vs) return;
    setSubmitting(true);
    try {
      await apiPost('/strategies/ab/experiments', {
        name: form.name,
        strategy_a: strategyName,
        strategy_b: form.vs,
        allocation_a: form.alloc,
        allocation_b: 100 - form.alloc,
      });
      setModalOpen(false);
      setForm({ name: '', vs: '', alloc: 50 });
      await fetchExperiments();
    } catch { /* silent */ }
    setSubmitting(false);
  };

  const statusColor = (st) => st === 'running' ? T.blue : st === 'concluded' ? T.green : T.amber;
  const statusLabel = (st) => st === 'running' ? 'Running' : st === 'concluded' ? 'Concluded' : 'Paused';

  return (
    <GlassPanel style={{ marginBottom: 24 }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
        <div className={s.panelTitle} style={{ marginBottom: 0 }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.purple} strokeWidth="2">
            <path d="M3 3h7v7H3z"/><path d="M14 3h7v7h-7z"/><path d="M3 14h7v7H3z"/>
            <path d="M17.5 14v6M14.5 17h6"/>
          </svg>
          A/B Experiments
        </div>
        <button
          onClick={() => setModalOpen(true)}
          style={{
            fontSize: 12, fontWeight: 600, padding: '5px 14px', borderRadius: 8,
            background: T.purple + '22', border: `1px solid ${T.purple}55`,
            color: T.purple, cursor: 'pointer',
          }}
        >
          + New Experiment
        </button>
      </div>

      {/* Table */}
      {experiments.length === 0 ? (
        <div style={{ fontSize: 13, color: T.textSec, padding: '12px 0' }}>
          No experiments for this strategy yet.
        </div>
      ) : (
        <div style={{ overflowX: 'auto' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13, fontFamily: T.mono }}>
            <thead>
              <tr style={{ borderBottom: `1px solid ${T.border}` }}>
                {['Experiment', 'Strategy A', 'Strategy B', 'Status', 'Split', 'Winner'].map(h => (
                  <th key={h} style={{ textAlign: 'left', padding: '4px 10px 6px', color: T.textSec, fontWeight: 600, fontSize: 11, textTransform: 'uppercase', letterSpacing: '0.05em' }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {experiments.map((e, i) => (
                <tr key={i} style={{ borderBottom: `1px solid ${T.border}22` }}>
                  <td style={{ padding: '6px 10px', color: T.text }}>{e.name || '--'}</td>
                  <td style={{ padding: '6px 10px', color: T.textSec }}>{e.strategy_a || '--'}</td>
                  <td style={{ padding: '6px 10px', color: T.textSec }}>{e.strategy_b || '--'}</td>
                  <td style={{ padding: '6px 10px' }}>
                    <span style={{ color: statusColor(e.status), background: statusColor(e.status) + '22', border: `1px solid ${statusColor(e.status)}44`, borderRadius: 6, padding: '2px 8px', fontSize: 11, fontWeight: 700 }}>
                      {statusLabel(e.status)}
                    </span>
                  </td>
                  <td style={{ padding: '6px 10px', color: T.textSec }}>
                    {e.allocation_a != null ? `${e.allocation_a}/${100 - e.allocation_a}` : '--'}
                  </td>
                  <td style={{ padding: '6px 10px', color: T.green, fontWeight: 700 }}>
                    {e.status === 'concluded' && e.winner ? <span>&#9733; {e.winner}</span> : <span style={{ color: T.textSec }}>--</span>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* New Experiment Modal */}
      {modalOpen && (
        <div style={{
          position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.65)', zIndex: 1000,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }} onClick={() => setModalOpen(false)}>
          <div onClick={e => e.stopPropagation()} style={{
            background: T.surface, border: `1px solid ${T.border}`, borderRadius: 16,
            padding: 28, width: 380, maxWidth: '90vw',
          }}>
            <div style={{ fontSize: 16, fontWeight: 700, color: T.text, marginBottom: 18 }}>New A/B Experiment</div>

            <label style={{ display: 'block', marginBottom: 12 }}>
              <span style={{ fontSize: 12, color: T.textSec, display: 'block', marginBottom: 4 }}>Experiment Name</span>
              <input
                value={form.name}
                onChange={e => setForm(f => ({ ...f, name: e.target.value }))}
                placeholder="e.g. Breakout vs Pullback Q2"
                style={{ width: '100%', padding: '8px 12px', borderRadius: 8, background: T.bg, border: `1px solid ${T.border}`, color: T.text, fontSize: 13, boxSizing: 'border-box' }}
              />
            </label>

            <label style={{ display: 'block', marginBottom: 12 }}>
              <span style={{ fontSize: 12, color: T.textSec, display: 'block', marginBottom: 4 }}>vs Strategy</span>
              <input
                value={form.vs}
                onChange={e => setForm(f => ({ ...f, vs: e.target.value }))}
                placeholder="Strategy B name"
                style={{ width: '100%', padding: '8px 12px', borderRadius: 8, background: T.bg, border: `1px solid ${T.border}`, color: T.text, fontSize: 13, boxSizing: 'border-box' }}
              />
            </label>

            <label style={{ display: 'block', marginBottom: 20 }}>
              <span style={{ fontSize: 12, color: T.textSec, display: 'block', marginBottom: 4 }}>
                Allocation to {strategyName}: <strong style={{ color: T.text }}>{form.alloc}%</strong> / {100 - form.alloc}%
              </span>
              <input
                type="range" min="10" max="90" value={form.alloc}
                onChange={e => setForm(f => ({ ...f, alloc: Number(e.target.value) }))}
                style={{ width: '100%', accentColor: T.purple }}
              />
            </label>

            <div style={{ display: 'flex', gap: 10, justifyContent: 'flex-end' }}>
              <button onClick={() => setModalOpen(false)} style={{ padding: '8px 18px', borderRadius: 8, background: 'transparent', border: `1px solid ${T.border}`, color: T.textSec, cursor: 'pointer', fontSize: 13 }}>
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                disabled={submitting || !form.name || !form.vs}
                style={{ padding: '8px 18px', borderRadius: 8, background: T.purple + '33', border: `1px solid ${T.purple}66`, color: T.purple, cursor: 'pointer', fontSize: 13, fontWeight: 700, opacity: (submitting || !form.name || !form.vs) ? 0.5 : 1 }}
              >
                {submitting ? 'Creating...' : 'Create'}
              </button>
            </div>
          </div>
        </div>
      )}
    </GlassPanel>
  );
}
