/* ═══════════════════════════════════════════════════════════════════════════
   AURA ALPHA — Strategy Decision Tree
   Visual flowchart showing WHY a strategy works: entry conditions, filters,
   and signal generation logic rendered as an SVG decision tree.
   ═══════════════════════════════════════════════════════════════════════════ */
import { useEffect, useRef, useState } from 'react';
import { tokens } from '../styles/tokens';

// ── Design tokens ─────────────────────────────────────────────────────────
const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  purple: tokens.color.purple, amber: tokens.color.amber, cyan: tokens.color.cyan,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

// ── Deterministic hash from strategy key → stable pseudo-random numbers ───
function hashCode(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h + str.charCodeAt(i)) | 0;
  }
  return Math.abs(h);
}

function seededRandom(seed) {
  let s = seed;
  return () => {
    s = (s * 16807 + 0) % 2147483647;
    return (s & 0x7fffffff) / 2147483647;
  };
}

function generatePassRate(strategyKey, nodeIndex) {
  const rand = seededRandom(hashCode(strategyKey || 'default') + nodeIndex * 137);
  // First node (scan) has high pass rate, subsequent nodes filter down
  const base = [95, 72, 58, 45, 38];
  const idx = Math.min(nodeIndex, base.length - 1);
  const jitter = Math.floor(rand() * 14) - 7;
  return Math.max(12, Math.min(98, base[idx] + jitter));
}

// ── Decision tree definitions per category ────────────────────────────────
const TREE_DEFS = {
  momentum: {
    scanLabel: 'Market Scan',
    nodes: [
      { question: 'Volume > 1.5x avg?', detail: 'Unusual volume filter' },
      { question: 'Price > 20-day high?', detail: 'Breakout confirmation' },
      { question: 'Score > threshold?', detail: 'Composite signal strength' },
    ],
    signal: 'BUY SIGNAL',
  },
  reversal: {
    scanLabel: 'Market Scan',
    nodes: [
      { question: 'Price dropped 3+ days?', detail: 'Pullback detection' },
      { question: 'RSI < 30?', detail: 'Oversold condition' },
      { question: 'Support level near?', detail: 'Key level proximity' },
    ],
    signal: 'BUY SIGNAL',
  },
  short: {
    scanLabel: 'Market Scan',
    nodes: [
      { question: 'Price at resistance?', detail: 'Overhead supply zone' },
      { question: 'Volume declining?', detail: 'Exhaustion signal' },
      { question: 'Bearish pattern?', detail: 'Candlestick / formation' },
    ],
    signal: 'SHORT SIGNAL',
  },
  crypto: {
    scanLabel: '24/7 Scan',
    nodes: [
      { question: 'Momentum cross?', detail: 'EMA / MACD crossover' },
      { question: 'Volume spike?', detail: 'Relative volume surge' },
      { question: 'Regime bullish?', detail: 'Trend regime filter' },
    ],
    signal: 'BUY SIGNAL',
  },
};

// Map strategy names / categories to tree type
function resolveTreeType(strategyKey, direction, category) {
  const k = (strategyKey || '').toLowerCase();
  const d = (direction || '').toLowerCase();
  const c = (category || '').toLowerCase();

  if (c === 'crypto' || d === 'crypto') return 'crypto';
  if (d === 'short') return 'short';

  // Reversal keywords
  const reversalKeys = [
    'pullback', 'bounce', 'snap back', 'reversal', 'horseshoe',
    'avwap', 'oversold', 'dip', '5 day',
  ];
  if (reversalKeys.some(rk => k.includes(rk))) return 'reversal';

  // Short keywords
  const shortKeys = [
    'cuts like', 'topping', 'downward', 'slippery', 'shorty',
    'failed bounce', 'bon shorty', 'knife',
  ];
  if (shortKeys.some(sk => k.includes(sk))) return 'short';

  // Default to momentum for long strategies
  return 'momentum';
}

// ── Layout constants ──────────────────────────────────────────────────────
const NODE_W = 170;
const NODE_H = 52;
const SKIP_W = 80;
const SKIP_H = 32;
const GAP_X = 36;
const GAP_Y = 24;
const ARROW_SIZE = 5;
const SVG_PAD = 16;

// ── SVG sub-components ────────────────────────────────────────────────────

function ArrowHead({ x, y, direction = 'right', color }) {
  const s = ARROW_SIZE;
  let points;
  if (direction === 'right') {
    points = `${x - s},${y - s} ${x},${y} ${x - s},${y + s}`;
  } else if (direction === 'down') {
    points = `${x - s},${y - s} ${x},${y} ${x + s},${y - s}`;
  }
  return <polygon points={points} fill={color} />;
}

function ConnectorLine({ x1, y1, x2, y2, color, dashed = false }) {
  return (
    <line
      x1={x1} y1={y1} x2={x2} y2={y2}
      stroke={color} strokeWidth={1.5}
      strokeDasharray={dashed ? '4 3' : 'none'}
      opacity={0.8}
    />
  );
}

function TreeNode({ x, y, w, h, label, sublabel, passRate, borderColor, fillColor, textColor, animDelay, isTerminal }) {
  const glow = isTerminal ? `drop-shadow(0 0 6px ${borderColor}44)` : 'none';

  return (
    <g style={{
      opacity: 0,
      animation: `fadeSlideIn 0.4s ease ${animDelay}s forwards`,
      filter: glow,
    }}>
      {/* Node background */}
      <rect
        x={x} y={y} width={w} height={h} rx={10}
        fill={fillColor}
        stroke={borderColor}
        strokeWidth={isTerminal ? 2 : 1}
      />
      {/* Label */}
      <text
        x={x + w / 2} y={y + (sublabel ? h * 0.40 : h * 0.52)}
        textAnchor="middle" dominantBaseline="middle"
        fill={textColor}
        fontSize={isTerminal ? 12 : 11}
        fontWeight={isTerminal ? 700 : 600}
        fontFamily={T.mono}
      >
        {label}
      </text>
      {/* Sublabel / pass rate */}
      {sublabel && (
        <text
          x={x + w / 2} y={y + h * 0.72}
          textAnchor="middle" dominantBaseline="middle"
          fill={T.textSec}
          fontSize={9}
          fontFamily={T.sans}
        >
          {sublabel}
        </text>
      )}
      {/* Pass rate badge (top-right) */}
      {passRate != null && !isTerminal && (
        <g>
          <rect
            x={x + w - 46} y={y - 8} width={42} height={16} rx={6}
            fill={T.surface2}
            stroke={T.border}
            strokeWidth={0.5}
          />
          <text
            x={x + w - 25} y={y + 1}
            textAnchor="middle" dominantBaseline="middle"
            fill={T.textSec}
            fontSize={8}
            fontWeight={600}
            fontFamily={T.mono}
          >
            {passRate}% pass
          </text>
        </g>
      )}
    </g>
  );
}

function SkipNode({ x, y, animDelay }) {
  return (
    <g style={{
      opacity: 0,
      animation: `fadeSlideIn 0.25s ease ${animDelay}s forwards`,
    }}>
      <rect
        x={x} y={y} width={SKIP_W} height={SKIP_H} rx={6}
        fill="transparent"
        stroke={T.textSec}
        strokeWidth={1}
        strokeDasharray="3 2"
        opacity={0.4}
      />
      <text
        x={x + SKIP_W / 2} y={y + SKIP_H / 2}
        textAnchor="middle" dominantBaseline="middle"
        fill={T.textSec}
        fontSize={10}
        fontFamily={T.mono}
        opacity={0.5}
      >
        Skip
      </text>
    </g>
  );
}

function YesNoLabel({ x, y, text, color, animDelay }) {
  return (
    <text
      x={x} y={y}
      textAnchor="middle" dominantBaseline="middle"
      fill={color}
      fontSize={9}
      fontWeight={700}
      fontFamily={T.mono}
      style={{
        opacity: 0,
        animation: `fadeSlideIn 0.25s ease ${animDelay}s forwards`,
      }}
    >
      {text}
    </text>
  );
}

// ── Main component ────────────────────────────────────────────────────────
export default function StrategyDecisionTree({ strategyKey, direction, category, stats }) {
  const containerRef = useRef(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  const treeType = resolveTreeType(strategyKey, direction, category);
  const treeDef = TREE_DEFS[treeType];
  const isShort = treeType === 'short';
  const signalColor = isShort ? T.red : T.green;
  const winRate = stats?.win_rate || stats?.avg_win_rate || null;

  // Calculate layout positions
  // Flow: [Scan] → [Node1] → [Node2] → [Node3] → [Signal]
  //                   ↓ NO       ↓ NO      ↓ NO
  //                 [Skip]     [Skip]    [Skip]
  const totalMainNodes = 1 + treeDef.nodes.length + 1; // scan + questions + terminal
  const totalW = SVG_PAD * 2 + totalMainNodes * NODE_W + (totalMainNodes - 1) * GAP_X;
  const skipRowY = SVG_PAD + NODE_H + GAP_Y + 10;
  const totalH = skipRowY + SKIP_H + SVG_PAD + 16;

  // X positions for each column
  const colX = (i) => SVG_PAD + i * (NODE_W + GAP_X);

  // Scan node position
  const scanX = colX(0);
  const scanY = SVG_PAD;

  // Question nodes
  const questionPositions = treeDef.nodes.map((_, i) => ({
    x: colX(i + 1),
    y: SVG_PAD,
  }));

  // Terminal signal node
  const terminalX = colX(treeDef.nodes.length + 1);
  const terminalY = SVG_PAD;

  // Skip node positions (below each question node)
  const skipPositions = treeDef.nodes.map((_, i) => ({
    x: colX(i + 1) + (NODE_W - SKIP_W) / 2,
    y: skipRowY,
  }));

  return (
    <div
      ref={containerRef}
      style={{
        marginBottom: 20,
        background: T.surface,
        borderRadius: 14,
        border: `1px solid ${T.border}`,
        padding: '16px 16px 12px',
        overflow: 'hidden',
        backdropFilter: 'blur(16px)',
        WebkitBackdropFilter: 'blur(16px)',
      }}
    >
      {/* Header */}
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        marginBottom: 12,
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke={T.purple} strokeWidth="2">
            <circle cx="12" cy="5" r="3" />
            <line x1="12" y1="8" x2="12" y2="14" />
            <line x1="12" y1="14" x2="6" y2="20" />
            <line x1="12" y1="14" x2="18" y2="20" />
          </svg>
          <span style={{ fontSize: 14, fontWeight: 700, fontFamily: T.sans, color: T.text }}>
            Decision Tree
          </span>
          <span style={{
            fontSize: 10, fontWeight: 600, padding: '2px 8px', borderRadius: 6,
            background: T.purple + '18', color: T.purple, fontFamily: T.mono,
            textTransform: 'capitalize',
          }}>
            {treeType}
          </span>
        </div>
        <span style={{ fontSize: 11, color: T.textSec, fontFamily: T.sans }}>
          Why this strategy triggers
        </span>
      </div>

      {/* SVG Decision Tree */}
      <svg
        width="100%"
        viewBox={`0 0 ${totalW} ${totalH}`}
        style={{ display: 'block', borderRadius: 10, background: T.surface2 }}
      >
        {/* Inject animation keyframes */}
        <defs>
          <style>{`
            @keyframes fadeSlideIn {
              from { opacity: 0; transform: translateY(6px); }
              to { opacity: 1; transform: translateY(0); }
            }
          `}</style>
        </defs>

        {/* ── Connecting lines (rendered first, behind nodes) ── */}

        {/* Scan → first question */}
        {mounted && (
          <g style={{ opacity: 0, animation: 'fadeSlideIn 0.25s ease 0.15s forwards' }}>
            <ConnectorLine
              x1={scanX + NODE_W} y1={scanY + NODE_H / 2}
              x2={questionPositions[0].x} y2={questionPositions[0].y + NODE_H / 2}
              color={T.blue}
            />
            <ArrowHead
              x={questionPositions[0].x}
              y={questionPositions[0].y + NODE_H / 2}
              direction="right" color={T.blue}
            />
          </g>
        )}

        {/* Question → next question (YES path) */}
        {mounted && questionPositions.map((pos, i) => {
          const nextX = i < questionPositions.length - 1
            ? questionPositions[i + 1].x
            : terminalX;
          const nextY = i < questionPositions.length - 1
            ? questionPositions[i + 1].y + NODE_H / 2
            : terminalY + NODE_H / 2;
          const delay = 0.2 + (i + 1) * 0.15;

          return (
            <g key={`yes-line-${i}`} style={{ opacity: 0, animation: `fadeSlideIn 0.25s ease ${delay}s forwards` }}>
              {/* YES horizontal line */}
              <ConnectorLine
                x1={pos.x + NODE_W} y1={pos.y + NODE_H / 2}
                x2={nextX} y2={nextY}
                color={T.green}
              />
              <ArrowHead x={nextX} y={nextY} direction="right" color={T.green} />
              {/* YES label */}
              <YesNoLabel
                x={pos.x + NODE_W + (nextX - pos.x - NODE_W) / 2}
                y={pos.y + NODE_H / 2 - 8}
                text="YES" color={T.green}
                animDelay={delay}
              />
            </g>
          );
        })}

        {/* Question → Skip (NO path, going down) */}
        {mounted && questionPositions.map((pos, i) => {
          const skipPos = skipPositions[i];
          const delay = 0.3 + (i + 1) * 0.15;
          const midX = pos.x + NODE_W / 2;

          return (
            <g key={`no-line-${i}`} style={{ opacity: 0, animation: `fadeSlideIn 0.25s ease ${delay}s forwards` }}>
              <ConnectorLine
                x1={midX} y1={pos.y + NODE_H}
                x2={midX} y2={skipPos.y}
                color={T.red} dashed
              />
              <ArrowHead x={midX} y={skipPos.y} direction="down" color={T.red} />
              {/* NO label */}
              <YesNoLabel
                x={midX + 14}
                y={pos.y + NODE_H + (skipPos.y - pos.y - NODE_H) / 2}
                text="NO" color={T.red}
                animDelay={delay}
              />
            </g>
          );
        })}

        {/* ── Nodes ── */}

        {/* Scan node */}
        {mounted && (
          <TreeNode
            x={scanX} y={scanY} w={NODE_W} h={NODE_H}
            label={treeDef.scanLabel}
            sublabel="Universe filter"
            passRate={generatePassRate(strategyKey, 0)}
            borderColor={T.blue}
            fillColor={T.surface}
            textColor={T.blue}
            animDelay={0.05}
          />
        )}

        {/* Question nodes */}
        {mounted && treeDef.nodes.map((node, i) => (
          <TreeNode
            key={`q-${i}`}
            x={questionPositions[i].x} y={questionPositions[i].y}
            w={NODE_W} h={NODE_H}
            label={node.question}
            sublabel={node.detail}
            passRate={generatePassRate(strategyKey, i + 1)}
            borderColor={T.amber}
            fillColor={T.surface}
            textColor={T.text}
            animDelay={0.1 + i * 0.15}
          />
        ))}

        {/* Terminal signal node */}
        {mounted && (
          <TreeNode
            x={terminalX} y={terminalY} w={NODE_W} h={NODE_H}
            label={treeDef.signal}
            sublabel={winRate != null ? `${Number(winRate).toFixed(1)}% win rate` : null}
            borderColor={signalColor}
            fillColor={signalColor + '18'}
            textColor={signalColor}
            animDelay={0.1 + treeDef.nodes.length * 0.15}
            isTerminal
          />
        )}

        {/* Skip nodes */}
        {mounted && treeDef.nodes.map((_, i) => (
          <SkipNode
            key={`skip-${i}`}
            x={skipPositions[i].x} y={skipPositions[i].y}
            animDelay={0.35 + i * 0.15}
          />
        ))}
      </svg>

      {/* ── Legend ── */}
      <div style={{
        marginTop: 8, padding: '6px 12px', borderRadius: 6,
        background: T.surface2, border: `1px solid ${T.border}`,
        opacity: 0.7,
      }}>
        <div style={{
          fontSize: 10, fontWeight: 600, color: T.textSec, marginBottom: 4,
          fontFamily: T.sans, textTransform: 'uppercase', letterSpacing: '0.06em',
        }}>
          How to read this
        </div>
        <div style={{
          display: 'flex', flexWrap: 'wrap', gap: 12, fontSize: 10, fontFamily: T.sans,
        }}>
          <LegendItem color={T.blue} label="Scan / entry point" />
          <LegendItem color={T.amber} borderStyle="solid" label="Filter condition" />
          <LegendItem color={T.green} label="YES path (passes)" lineStyle="solid" />
          <LegendItem color={T.red} label="NO path (skip)" lineStyle="dashed" />
          <LegendItem color={signalColor} filled label={isShort ? 'Short signal' : 'Buy signal'} />
        </div>
      </div>
    </div>
  );
}

// ── Legend item ────────────────────────────────────────────────────────────
function LegendItem({ color, label, filled, lineStyle }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
      {lineStyle ? (
        <svg width="20" height="10" viewBox="0 0 20 10">
          <line
            x1="0" y1="5" x2="16" y2="5"
            stroke={color} strokeWidth={2}
            strokeDasharray={lineStyle === 'dashed' ? '3 2' : 'none'}
          />
          <polygon points="16,2 20,5 16,8" fill={color} />
        </svg>
      ) : (
        <span style={{
          display: 'inline-block', width: 10, height: 10, borderRadius: 6,
          background: filled ? color + '28' : 'transparent',
          border: `1.5px solid ${color}`,
        }} />
      )}
      <span style={{ color: T.textSec }}>{label}</span>
    </div>
  );
}
